6	"use strict";
7	
8	const ModuleGraphConnection = require("./ModuleGraphConnection");
9	const AsyncDependencyToInitialChunkError = require("./errors/AsyncDependencyToInitialChunkError");
10	const { getEntryRuntime, mergeRuntime } = require("./util/runtime");
11	
12	/** @typedef {import("./AsyncDependenciesBlock")} AsyncDependenciesBlock */
13	/** @typedef {import("./Chunk")} Chunk */
14	/** @typedef {import("./ChunkGroup")} ChunkGroup */
15	/** @typedef {import("./Compilation")} Compilation */
16	/** @typedef {import("./DependenciesBlock")} DependenciesBlock */
17	/** @typedef {import("./Dependency").DependencyLocation} DependencyLocation */
18	/** @typedef {import("./Entrypoint")} Entrypoint */
19	/** @typedef {import("./Entrypoint").EntryOptions} EntryOptions */
20	/** @typedef {import("./Module")} Module */
21	/** @typedef {import("./ModuleGraph")} ModuleGraph */
22	/** @typedef {import("./ModuleGraphConnection").ConnectionState} ConnectionState */
23	/** @typedef {import("./logging/Logger").Logger} Logger */
24	/** @typedef {import("./util/runtime").RuntimeSpec} RuntimeSpec */
25	
26	/**
27	 * Defines the queue item type used by this module.
28	 * @typedef {object} QueueItem
29	 * @property {number} action
30	 * @property {DependenciesBlock} block
31	 * @property {Module} module
32	 * @property {Chunk} chunk
33	 * @property {ChunkGroup} chunkGroup
34	 * @property {ChunkGroupInfo} chunkGroupInfo
35	 */
36	
37	/**
38	 * Defines the chunk group info type used by this module.
39	 * @typedef {object} ChunkGroupInfo
40	 * @property {ChunkGroup} chunkGroup the chunk group
41	 * @property {RuntimeSpec} runtime the runtimes
42	 * @property {boolean} initialized is this chunk group initialized
43	 * @property {bigint | undefined} minAvailableModules current minimal set of modules available at this point
44	 * @property {bigint[]} availableModulesToBeMerged enqueued updates to the minimal set of available modules
45	 * @property {Set<Module>=} skippedItems modules that were skipped because module is already available in parent chunks (need to reconsider when minAvailableModules is shrinking)
46	 * @property {Set<[Module, ModuleGraphConnection[]]>=} skippedModuleConnections referenced modules that where skipped because they were not active in this runtime
47	 * @property {bigint | undefined} resultingAvailableModules set of modules available including modules from this chunk group
48	 * @property {Set<ChunkGroupInfo> | undefined} children set of children chunk groups, that will be revisited when availableModules shrink
49	 * @property {Set<ChunkGroupInfo> | undefined} availableSources set of chunk groups that are the source for minAvailableModules
50	 * @property {Set<ChunkGroupInfo> | undefined} availableChildren set of chunk groups which depend on the this chunk group as availableSource
51	 * @property {number} preOrderIndex next pre order index
52	 * @property {number} postOrderIndex next post order index
53	 * @property {boolean} chunkLoading has a chunk loading mechanism
54	 * @property {boolean} asyncChunks create async chunks
55	 * @property {Module | null} depModule the module that is the dependency of the block
56	 * @property {boolean} circular Whether to deduplicate to avoid circular references
57	 */
58	
59	/**
60	 * Defines the block chunk group connection type used by this module.
61	 * @typedef {object} BlockChunkGroupConnection
62	 * @property {ChunkGroupInfo} originChunkGroupInfo origin chunk group
63	 * @property {ChunkGroup} chunkGroup referenced chunk group
64	 */
65	
66	/** @typedef {(Module | ConnectionState | ModuleGraphConnection)[]} BlockModulesInTuples */
67	/** @typedef {(Module | ConnectionState | ModuleGraphConnection[])[]} BlockModulesInFlattenTuples */
68	/** @typedef {Map<DependenciesBlock, BlockModulesInFlattenTuples>} BlockModulesMap */
69	/** @typedef {Map<Chunk, bigint>} MaskByChunk */
70	/** @typedef {Set<DependenciesBlock>} BlocksWithNestedBlocks */
71	/** @typedef {Map<AsyncDependenciesBlock, BlockChunkGroupConnection[]>} BlockConnections */
72	/** @typedef {Map<ChunkGroup, ChunkGroupInfo>} ChunkGroupInfoMap */
73	/** @typedef {Set<ChunkGroup>} AllCreatedChunkGroups */
74	/** @typedef {Map<Entrypoint, Module[]>} InputEntrypointsAndModules */
75	
76	const ZERO_BIGINT = BigInt(0);
77	const ONE_BIGINT = BigInt(1);
78	
79	/**
80	 * Checks whether this object is ordinal set in mask.
81	 * @param {bigint} mask The mask to test
82	 * @param {number} ordinal The ordinal of the bit to test
83	 * @returns {boolean} If the ordinal-th bit is set in the mask
84	 */
85	const isOrdinalSetInMask = (mask, ordinal) =>
86		BigInt.asUintN(1, mask >> BigInt(ordinal)) !== ZERO_BIGINT;
87	
88	/**
89	 * Gets active state of connections.
90	 * @param {ModuleGraphConnection[]} connections list of connections
91	 * @param {RuntimeSpec} runtime for which runtime
92	 * @returns {ConnectionState} connection state
93	 */
94	const getActiveStateOfConnections = (connections, runtime) => {
95		let merged = connections[0].getActiveState(runtime);
96		if (merged === true) return true;
97		for (let i = 1; i < connections.length; i++) {
98			const c = connections[i];
99			merged = ModuleGraphConnection.addConnectionStates(
100				merged,
101				c.getActiveState(runtime)
102			);
103			if (merged === true) return true;
104		}
105		return merged;
106	};
107	
108	/**
109	 * Extract block modules.
110	 * @param {Module} module module
111	 * @param {ModuleGraph} moduleGraph module graph
112	 * @param {RuntimeSpec} runtime runtime
113	 * @param {BlockModulesMap} blockModulesMap block modules map
114	 */
115	const extractBlockModules = (module, moduleGraph, runtime, blockModulesMap) => {
116		/** @type {DependenciesBlock | undefined} */
117		let blockCache;
118		/** @type {BlockModulesInTuples | undefined} */
119		let modules;
120	
121		/** @type {BlockModulesInTuples[]} */
122		const arrays = [];
123	
124		/** @type {DependenciesBlock[]} */
125		const queue = [module];
126		while (queue.length > 0) {
127			const block = /** @type {DependenciesBlock} */ (queue.pop());
128			/** @type {Module[]} */
129			const arr = [];
130			arrays.push(arr);
131			blockModulesMap.set(block, arr);
132			for (const b of block.blocks) {
133				queue.push(b);
134			}
135		}
136	
137		for (const connection of moduleGraph.getOutgoingConnections(module)) {
138			const d = connection.dependency;
139			// We skip connections without dependency
140			if (!d) continue;
141			const m = connection.module;
142			// We skip connections without Module pointer
143			if (!m) continue;
144			// We skip weak connections
145			if (connection.weak) continue;
146	
147			const block = moduleGraph.getParentBlock(d);
148			let index = moduleGraph.getParentBlockIndex(d);
149	
150			// deprecated fallback
151			if (index < 0) {
152				index = /** @type {DependenciesBlock} */ (block).dependencies.indexOf(d);
153			}
154	
155			if (blockCache !== block) {
156				modules =
157					/** @type {BlockModulesInTuples} */
158					(
159						blockModulesMap.get(
160							(blockCache = /** @type {DependenciesBlock} */ (block))
161						)
162					);
163			}
164	
165			const i = index * 3;
166			/** @type {BlockModulesInTuples} */
167			(modules)[i] = m;
168			/** @type {BlockModulesInTuples} */
169			(modules)[i + 1] = connection.getActiveState(runtime);
170			/** @type {BlockModulesInTuples} */
171			(modules)[i + 2] = connection;
172		}
173	
174		for (const modules of arrays) {
175			if (modules.length === 0) continue;
176			/** @type {undefined | Map<Module | ModuleGraphConnection | ConnectionState, number>} */
177			let indexMap;
178			let length = 0;
179			outer: for (let j = 0; j < modules.length; j += 3) {
180				const m = modules[j];
181				if (m === undefined) continue;
182				const state = /** @type {ConnectionState} */ (modules[j + 1]);
183				const connection = /** @type {ModuleGraphConnection} */ (modules[j + 2]);
184				if (indexMap === undefined) {
185					let i = 0;
186					for (; i < length; i += 3) {
187						if (modules[i] === m) {
188							const merged = /** @type {ConnectionState} */ (modules[i + 1]);
189							/** @type {ModuleGraphConnection[]} */
190							(/** @type {unknown} */ (modules[i + 2])).push(connection);
191							if (merged === true) continue outer;
192							modules[i + 1] = ModuleGraphConnection.addConnectionStates(
193								merged,
194								state
195							);
196							continue outer;
197						}
198					}
199					modules[length] = m;
200					length++;
201					modules[length] = state;
202					length++;
203					/** @type {ModuleGraphConnection[]} */
204					(/** @type {unknown} */ (modules[length])) = [connection];
205					length++;
206					if (length > 30) {
207						// To avoid worse case performance, we will use an index map for
208						// linear cost access, which allows to maintain O(n) complexity
209						// while keeping allocations down to a minimum
210						indexMap = new Map();
211						for (let i = 0; i < length; i += 3) {
212							indexMap.set(modules[i], i + 1);
213						}
214					}
215				} else {
216					const idx = indexMap.get(m);
217					if (idx !== undefined) {
218						const merged = /** @type {ConnectionState} */ (modules[idx]);
219						/** @type {ModuleGraphConnection[]} */
220						(/** @type {unknown} */ (modules[idx + 1])).push(connection);
221						if (merged === true) continue;
222						modules[idx] = ModuleGraphConnection.addConnectionStates(
223							merged,
224							state
225						);
226					} else {
227						modules[length] = m;
228						length++;
229						modules[length] = state;
230						indexMap.set(m, length);
231						length++;
232						/** @type {ModuleGraphConnection[]} */
233						(
234							/** @type {unknown} */
235							(modules[length])
236						) = [connection];
237						length++;
238					}
239				}
240			}
241			modules.length = length;
242		}
243	};
244	
245	/**
246	 * Derives block modules for another runtime from an already extracted result.
247	 * Only the merged active state of each connection group can differ per
248	 * runtime; modules and connection groups are reused. When all states turn
249	 * out equal, the tuple array is shared instead of copied.
250	 * @param {Module} module the root module
251	 * @param {BlockModulesMap} source map containing the extracted result for all blocks of the module
252	 * @param {RuntimeSpec} runtime runtime to derive for
253	 * @param {BlockModulesMap} blockModulesMap block modules map to fill
254	 */
255	const deriveBlockModules = (module, source, runtime, blockModulesMap) => {
256		/** @type {DependenciesBlock[]} */
257		const queue = [module];
258		while (queue.length > 0) {
259			const block = /** @type {DependenciesBlock} */ (queue.pop());
260			const sourceModules =
261				/** @type {BlockModulesInFlattenTuples} */
262				(source.get(block));
263			let target = sourceModules;
264			for (let i = 0, len = sourceModules.length; i < len; i += 3) {
265				const state = getActiveStateOfConnections(
266					/** @type {ModuleGraphConnection[]} */ (sourceModules[i + 2]),
267					runtime
268				);
269				if (target === sourceModules) {
270					if (state === sourceModules[i + 1]) continue;
271					// states diverged, copy (states before i are identical)
272					target = [...sourceModules];
273				}
274				target[i + 1] = state;
275			}
276			blockModulesMap.set(block, target);
277			for (const b of block.blocks) {
278				queue.push(b);
279			}
280		}
281	};
282	
283	/**
284	 * Processes the provided logger.
285	 * @param {Logger} logger a logger
286	 * @param {Compilation} compilation the compilation
287	 * @param {InputEntrypointsAndModules} inputEntrypointsAndModules chunk groups which are processed with the modules
288	 * @param {ChunkGroupInfoMap} chunkGroupInfoMap mapping from chunk group to available modules
289	 * @param {BlockConnections} blockConnections connection for blocks
290	 * @param {BlocksWithNestedBlocks} blocksWithNestedBlocks flag for blocks that have nested blocks
291	 * @param {AllCreatedChunkGroups} allCreatedChunkGroups filled with all chunk groups that are created here
292	 * @param {MaskByChunk} maskByChunk module content mask by chunk
293	 */
294	const visitModules = (
295		logger,
296		compilation,
297		inputEntrypointsAndModules,
298		chunkGroupInfoMap,
299		blockConnections,
300		blocksWithNestedBlocks,
301		allCreatedChunkGroups,
302		maskByChunk
303	) => {
304		const { moduleGraph, chunkGraph, moduleMemCaches } = compilation;
305	
306		/** @type {Map<RuntimeSpec, BlockModulesMap>} */
307		const blockModulesRuntimeMap = new Map();
308	
309		// map containing the first extraction per root module,
310		// other runtimes derive their result from it
311		/** @type {Map<Module, BlockModulesMap>} */
312		const firstBlockModulesMapByModule = new Map();
313	
314		/** @type {Map<Module, number>} */
315		const ordinalByModule = new Map();
316	
317		/**
318		 * Gets module ordinal.
319		 * @param {Module} module The module to look up
320		 * @returns {number} The ordinal of the module in masks
321		 */
322		const getModuleOrdinal = (module) => {
323			let ordinal = ordinalByModule.get(module);
324			if (ordinal === undefined) {
325				ordinal = ordinalByModule.size;
326				ordinalByModule.set(module, ordinal);
327			}
328			return ordinal;
329		};
330	
331		for (const chunk of compilation.chunks) {
332			let mask = ZERO_BIGINT;
333			for (const m of chunkGraph.getChunkModulesIterable(chunk)) {
334				mask |= ONE_BIGINT << BigInt(getModuleOrdinal(m));
335			}
336			maskByChunk.set(chunk, mask);
337		}
338	
339		/**
340		 * Gets block modules.
341		 * @param {DependenciesBlock} block block
342		 * @param {RuntimeSpec} runtime runtime
343		 * @returns {BlockModulesInFlattenTuples | undefined} block modules in flatten tuples
344		 */
345		const getBlockModules = (block, runtime) => {
346			let blockModulesMap = blockModulesRuntimeMap.get(runtime);
347			if (blockModulesMap === undefined) {
348				/** @type {BlockModulesMap} */
349				blockModulesMap = new Map();
350				blockModulesRuntimeMap.set(runtime, blockModulesMap);
351			}
352			let blockModules = blockModulesMap.get(block);
353			if (blockModules !== undefined) return blockModules;
354			const module = /** @type {Module} */ (block.getRootBlock());
355			const memCache = moduleMemCaches && moduleMemCaches.get(module);
356			if (memCache !== undefined) {
357				/** @type {BlockModulesMap} */
358				const map = memCache.provide(
359					"bundleChunkGraph.blockModules",
360					runtime,
361					() => {
362						logger.time("visitModules: prepare");
363						const map = new Map();
364						const source = firstBlockModulesMapByModule.get(module);
365						if (source !== undefined) {
366							deriveBlockModules(module, source, runtime, map);
367						} else {
368							extractBlockModules(module, moduleGraph, runtime, map);
369						}
370						logger.timeAggregate("visitModules: prepare");
371						return map;
372					}
373				);
374				// allow other runtimes to derive from a memCache hit too
375				if (!firstBlockModulesMapByModule.has(module)) {
376					firstBlockModulesMapByModule.set(module, map);
377				}
378				for (const [block, blockModules] of map) {
379					blockModulesMap.set(block, blockModules);
380				}
381				return map.get(block);
382			}
383			logger.time("visitModules: prepare");
384			const source = firstBlockModulesMapByModule.get(module);
385			if (source !== undefined) {
386				deriveBlockModules(module, source, runtime, blockModulesMap);
387			} else {
388				extractBlockModules(module, moduleGraph, runtime, blockModulesMap);
389				firstBlockModulesMapByModule.set(module, blockModulesMap);
390			}
391			blockModules =
392				/** @type {BlockModulesInFlattenTuples} */
393				(blockModulesMap.get(block));
394			logger.timeAggregate("visitModules: prepare");
395			return blockModules;
396		};
397	
398		let statProcessedQueueItems = 0;
399		let statProcessedBlocks = 0;
400		let statConnectedChunkGroups = 0;
401		let statProcessedChunkGroupsForMerging = 0;
402		let statMergedAvailableModuleSets = 0;
403		const statForkedAvailableModules = 0;
404		const statForkedAvailableModulesCount = 0;
405		const statForkedAvailableModulesCountPlus = 0;
406		const statForkedMergedModulesCount = 0;
407		const statForkedMergedModulesCountPlus = 0;
408		const statForkedResultModulesCount = 0;
409		let statChunkGroupInfoUpdated = 0;
410		let statChildChunkGroupsReconnected = 0;
411	
412		let nextChunkGroupIndex = 0;
413		let nextFreeModulePreOrderIndex = 0;
414		let nextFreeModulePostOrderIndex = 0;
415	
416		/** @type {Map<DependenciesBlock, ChunkGroupInfo>} */
417		const blockChunkGroups = new Map();
418	
419		/** @type {Map<ChunkGroupInfo, Set<DependenciesBlock>>} */
420		const blocksByChunkGroups = new Map();
421	
422		/** @typedef {Map<string, ChunkGroupInfo>} NamedChunkGroup */
423	
424		/** @type {NamedChunkGroup} */
425		const namedChunkGroups = new Map();
426	
427		/** @type {NamedChunkGroup} */
428		const namedAsyncEntrypoints = new Map();
429	
430		/** @type {Map<Module, ChunkGroupInfo>} */
431		const depModuleAsyncEntrypoints = new Map();
432	
433		/** @type {Set<ChunkGroupInfo>} */
434		const outdatedOrderIndexChunkGroups = new Set();
435	
436		const ADD_AND_ENTER_ENTRY_MODULE = 0;
437		const ADD_AND_ENTER_MODULE = 1;
438		const ENTER_MODULE = 2;
439		const PROCESS_BLOCK = 3;
440		const PROCESS_ENTRY_BLOCK = 4;
441		const LEAVE_MODULE = 5;
442	
443		/** @type {QueueItem[]} */
444		let queue = [];
445	
446		/** @typedef {Set<[ChunkGroupInfo, QueueItem | null]>} ConnectList */
447		/** @type {Map<ChunkGroupInfo, ConnectList>} */
448		const queueConnect = new Map();
449		/** @type {Set<ChunkGroupInfo>} */
450		const chunkGroupsForCombining = new Set();
451	
452		// Fill queue with entrypoint modules
453		// Create ChunkGroupInfo for entrypoints
454		for (const [chunkGroup, modules] of inputEntrypointsAndModules) {
455			const runtime = getEntryRuntime(
456				compilation,
457				/** @type {string} */ (chunkGroup.name),
458				chunkGroup.options
459			);
460			/** @type {ChunkGroupInfo} */
461			const chunkGroupInfo = {
462				depModule: null,
463				circular: false,
464				initialized: false,
465				chunkGroup,
466				runtime,
467				minAvailableModules: undefined,
468				availableModulesToBeMerged: [],
469				skippedItems: undefined,
470				resultingAvailableModules: undefined,
471				children: undefined,
472				availableSources: undefined,
473				availableChildren: undefined,
474				preOrderIndex: 0,
475				postOrderIndex: 0,
476				chunkLoading:
477					chunkGroup.options.chunkLoading !== undefined
478						? chunkGroup.options.chunkLoading !== false
479						: compilation.outputOptions.chunkLoading !== false,
480				asyncChunks:
481					chunkGroup.options.asyncChunks !== undefined
482						? chunkGroup.options.asyncChunks
483						: compilation.outputOptions.asyncChunks !== false
484			};
485			chunkGroup.index = nextChunkGroupIndex++;
486			if (chunkGroup.getNumberOfParents() > 0) {
487				// minAvailableModules for child entrypoints are unknown yet, set to undefined.
488				// This means no module is added until other sets are merged into
489				// this minAvailableModules (by the parent entrypoints)
490				const skippedItems = new Set(modules);
491				chunkGroupInfo.skippedItems = skippedItems;
492				chunkGroupsForCombining.add(chunkGroupInfo);
493			} else {
494				// The application may start here: We start with an empty list of available modules
495				chunkGroupInfo.minAvailableModules = ZERO_BIGINT;
496				const chunk = chunkGroup.getEntrypointChunk();
497				for (const module of modules) {
498					queue.push({
499						action: ADD_AND_ENTER_MODULE,
500						block: module,
501						module,
502						chunk,
503						chunkGroup,
504						chunkGroupInfo
505					});
506				}
507			}
508			chunkGroupInfoMap.set(chunkGroup, chunkGroupInfo);
509			if (chunkGroup.name) {
510				namedChunkGroups.set(chunkGroup.name, chunkGroupInfo);
511			}
512		}
513		// Fill availableSources with parent-child dependencies between entrypoints
514		for (const chunkGroupInfo of chunkGroupsForCombining) {
515			const { chunkGroup } = chunkGroupInfo;
516			chunkGroupInfo.availableSources = new Set();
517			for (const parent of chunkGroup.parentsIterable) {
518				const parentChunkGroupInfo =
519					/** @type {ChunkGroupInfo} */
520					(chunkGroupInfoMap.get(parent));
521				chunkGroupInfo.availableSources.add(parentChunkGroupInfo);
522				if (parentChunkGroupInfo.availableChildren === undefined) {
523					parentChunkGroupInfo.availableChildren = new Set();
524				}
525				parentChunkGroupInfo.availableChildren.add(chunkGroupInfo);
526			}
527		}
528		// pop() is used to read from the queue
529		// so it need to be reversed to be iterated in
530		// correct order
531		queue.reverse();
532	
533		/** @type {Set<ChunkGroupInfo>} */
534		const outdatedChunkGroupInfo = new Set();
535		/** @type {Set<[ChunkGroupInfo, QueueItem | null]>} */
536		const chunkGroupsForMerging = new Set();
537		/** @type {QueueItem[]} */
538		let queueDelayed = [];
539	
540		/** @type {[Module, ModuleGraphConnection[]][]} */
541		const skipConnectionBuffer = [];
542		/** @type {Module[]} */
543		const skipBuffer = [];
544		/** @type {QueueItem[]} */
545		const queueBuffer = [];
546	
547		/** @type {Module} */
548		let module;
549		/** @type {Chunk} */
550		let chunk;
551		/** @type {ChunkGroup} */
552		let chunkGroup;
553		/** @type {DependenciesBlock} */
554		let block;
555		/** @type {ChunkGroupInfo} */
556		let chunkGroupInfo;
557	
558		// For each async Block in graph
559		/**
560		 * Processes the provided b.
561		 * @param {AsyncDependenciesBlock} b iterating over each Async DepBlock
562		 * @returns {void}
563		 */
564		const iteratorBlock = (b) => {
565			// 1. We create a chunk group with single chunk in it for this Block
566			// but only once (blockChunkGroups map)
567			/** @type {ChunkGroupInfo | undefined} */
568			let cgi = blockChunkGroups.get(b);
569			/** @type {ChunkGroup | undefined} */
570			let c;
571			/** @type {Entrypoint | undefined} */
572			let entrypoint;
573			/** @type {Module | null} */
574			const depModule = moduleGraph.getModule(b.dependencies[0]);
575			const entryOptions = b.groupOptions && b.groupOptions.entryOptions;
576			if (cgi === undefined) {
577				const chunkName = (b.groupOptions && b.groupOptions.name) || b.chunkName;
578				if (entryOptions) {
579					cgi = namedAsyncEntrypoints.get(/** @type {string} */ (chunkName));
580					if (!cgi && !b.circular && depModule) {
581						cgi = depModuleAsyncEntrypoints.get(depModule);
582					}
583					if (!cgi) {
584						entrypoint = compilation.addAsyncEntrypoint(
585							entryOptions,
586							module,
587							/** @type {DependencyLocation} */ (b.loc),
588							/** @type {string} */ (b.request)
589						);
590						maskByChunk.set(entrypoint.chunks[0], ZERO_BIGINT);
591						entrypoint.index = nextChunkGroupIndex++;
592						cgi = {
593							depModule,
594							circular: b.circular,
595							chunkGroup: entrypoint,
596							initialized: false,
597							runtime:
598								entrypoint.options.runtime ||
599								/** @type {string | undefined} */ (entrypoint.name),
600							minAvailableModules: ZERO_BIGINT,
601							availableModulesToBeMerged: [],
602							skippedItems: undefined,
603							resultingAvailableModules: undefined,
604							children: undefined,
605							availableSources: undefined,
606							availableChildren: undefined,
607							preOrderIndex: 0,
608							postOrderIndex: 0,
609							chunkLoading:
610								entryOptions.chunkLoading !== undefined
611									? entryOptions.chunkLoading !== false
612									: chunkGroupInfo.chunkLoading,
613							asyncChunks:
614								entryOptions.asyncChunks !== undefined
