1321		logger.log(
1322			`${statProcessedQueueItems} queue items processed (${statProcessedBlocks} blocks)`
1323		);
1324		logger.log(`${statConnectedChunkGroups} chunk groups connected`);
1325		logger.log(
1326			`${statProcessedChunkGroupsForMerging} chunk groups processed for merging (${statMergedAvailableModuleSets} module sets, ${statForkedAvailableModules} forked, ${statForkedAvailableModulesCount} + ${statForkedAvailableModulesCountPlus} modules forked, ${statForkedMergedModulesCount} + ${statForkedMergedModulesCountPlus} modules merged into fork, ${statForkedResultModulesCount} resulting modules)`
