1811		/**
1812		 * Get module graph hash with connections.
1813		 * @param {ChunkGraphModule} cgm the ChunkGraphModule
1814		 * @param {Module} module the module
1815		 * @param {RuntimeSpec} runtime the runtime
1816		 * @returns {string} hash
1817		 */
1818		_getModuleGraphHashWithConnections(cgm, module, runtime) {
1819			if (cgm.graphHashesWithConnections === undefined) {
1820				cgm.graphHashesWithConnections = new RuntimeSpecMap();
1821			}
1822	
1823			/**
1824			 * Active state to string.
1825			 * @param {ConnectionState} state state
1826			 * @returns {"F" | "T" | "O"} result
1827			 */
1828			const activeStateToString = (state) => {
1829				if (state === false) return "F";
1830				if (state === true) return "T";
1831				if (state === ModuleGraphConnection.TRANSITIVE_ONLY) return "O";
1832				throw new Error("Not implemented active state");
1833			};
1834			const strict =
1835				module.buildMeta &&
1836				/** @type {JavascriptModuleBuildMeta} */ (module.buildMeta)
1837					.strictHarmonyModule;
1838			return cgm.graphHashesWithConnections.provide(runtime, () => {
1839				const graphHash = this._getModuleGraphHashBigInt(
1840					cgm,
1841					module,
1842					runtime
1843				).toString(16);
1844				const connections = this.moduleGraph.getOutgoingConnections(module);
1845				/** @type {Set<Module>} */
1846				const activeNamespaceModules = new Set();
1847				/** @type {Map<string, Module | Set<Module>>} */
1848				const connectedModules = new Map();
1849				/**
1850				 * Process connection.
1851				 * @param {ModuleGraphConnection} connection connection
1852				 * @param {string} stateInfo state info
1853				 */
1854				const processConnection = (connection, stateInfo) => {
1855					const module = connection.module;
1856					stateInfo += module.getExportsType(this.moduleGraph, strict);
1857					// cspell:word Tnamespace
1858					if (stateInfo === "Tnamespace") {
1859						activeNamespaceModules.add(module);
1860					} else {
1861						const oldModule = connectedModules.get(stateInfo);
1862						if (oldModule === undefined) {
1863							connectedModules.set(stateInfo, module);
1864						} else if (oldModule instanceof Set) {
1865							oldModule.add(module);
1866						} else if (oldModule !== module) {
1867							connectedModules.set(stateInfo, new Set([oldModule, module]));
1868						}
1869					}
1870				};
1871				if (runtime === undefined || typeof runtime === "string") {
1872					for (const connection of connections) {
1873						const state = connection.getActiveState(runtime);
1874						if (state === false) continue;
1875						processConnection(connection, state === true ? "T" : "O");
1876					}
1877				} else {
1878					// cspell:word Tnamespace
1879					for (const connection of connections) {
1880						/** @type {Set<ConnectionState>} */
1881						const states = new Set();
1882						let stateInfo = "";
1883						forEachRuntime(
1884							runtime,
1885							(runtime) => {
1886								const state = connection.getActiveState(runtime);
1887								states.add(state);
1888								stateInfo += activeStateToString(state) + runtime;
1889							},
1890							true
1891						);
1892						if (states.size === 1) {
1893							const state = first(states);
1894							if (state === false) continue;
1895							stateInfo = activeStateToString(
1896								/** @type {ConnectionState} */
1897								(state)
1898							);
1899						}
1900						processConnection(connection, stateInfo);
1901					}
1902				}
1903				// cspell:word Tnamespace
1904				if (activeNamespaceModules.size === 0 && connectedModules.size === 0) {
1905					return graphHash;
1906				}
1907				const connectedModulesInOrder =
1908					connectedModules.size > 1
1909						? [...connectedModules].sort(([a], [b]) => (a < b ? -1 : 1))
1910						: connectedModules;
1911				const hash = createHash(this._hashFunction);
1912				/**
1913				 * Adds module to hash.
1914				 * @param {Module} module module
1915				 */
1916				const addModuleToHash = (module) => {
1917					hash.update(
1918						this._getModuleGraphHashBigInt(
1919							this._getChunkGraphModule(module),
1920							module,
1921							runtime
1922						).toString(16)
1923					);
1924				};
1925				/**
1926				 * Adds modules to hash.
1927				 * @param {Set<Module>} modules modules
1928				 */
1929				const addModulesToHash = (modules) => {
1930					let xor = ZERO_BIG_INT;
1931					for (const m of modules) {
1932						xor ^= this._getModuleGraphHashBigInt(
1933							this._getChunkGraphModule(m),
1934							m,
1935							runtime
1936						);
1937					}
1938					hash.update(xor.toString(16));
1939				};
1940				if (activeNamespaceModules.size === 1) {
1941					addModuleToHash(
1942						/** @type {Module} */ (activeNamespaceModules.values().next().value)
1943					);
1944				} else if (activeNamespaceModules.size > 1) {
1945					addModulesToHash(activeNamespaceModules);
1946				}
1947				for (const [stateInfo, modules] of connectedModulesInOrder) {
1948					hash.update(stateInfo);
1949					if (modules instanceof Set) {
1950						addModulesToHash(modules);
1951					} else {
1952						addModuleToHash(modules);
1953					}
1954				}
1955				hash.update(graphHash);
1956				return hash.digest("hex");
1957			});
1958		}
